from dataclasses import dataclass
from typing import Any, Dict, List, Optional

@dataclass
class OnlineFeatureRequest:
    entity_id: str
    feature_names: List[str]

@dataclass
class OnlineFeatureResult:
    entity_id: str
    features: Dict[str, Any]    # feature_name → current value
    missing: List[str]          # features that were not found

class OnlineFeatureStore:
    def get(self, request: OnlineFeatureRequest) -> OnlineFeatureResult:
        raise NotImplementedError

class LLMContextBuilder:
    """
    Fetches user features from the online store and formats them
    for injection into an LLM system prompt.
    """
    def __init__(self, store: OnlineFeatureStore):
        self.store = store

    FEATURES = [
        "user_subscription_tier",
        "user_preferred_language",
        "user_account_age_days",
        "user_open_ticket_count",
        "user_30d_spend_usd",
        "user_last_contact_sentiment",   # pre-computed: positive/neutral/negative
    ]

    def build_context(self, user_id: str) -> str:
        result = self.store.get(OnlineFeatureRequest(
            entity_id=user_id,
            feature_names=self.FEATURES,
        ))
        f = result.features
        lines = ["[USER CONTEXT]"]
        if "user_subscription_tier" in f:
            lines.append(f"- Subscription: {f['user_subscription_tier']}")
        if "user_open_ticket_count" in f:
            lines.append(f"- Open support tickets: {f['user_open_ticket_count']}")
        if "user_30d_spend_usd" in f:
            lines.append(f"- 30-day spend: USD {f['user_30d_spend_usd']:.2f}")
        if "user_last_contact_sentiment" in f:
            lines.append(f"- Last contact sentiment: {f['user_last_contact_sentiment']}")
        return "\n".join(lines)

    def build_system_prompt(self, base_prompt: str, user_id: str) -> str:
        context = self.build_context(user_id)
        return f"{base_prompt}\n\n{context}"

import json, time
from typing import Any, Dict, List, Optional

class RedisFeatureStore:
    """
    Lightweight online feature store backed by Redis.
    Key format: feature:<entity_type>:<entity_id>:<feature_name>
    """
    def __init__(self, redis_client, entity_type: str = "user", ttl_seconds: int = 86400):
        self.r = redis_client
        self.entity_type = entity_type
        self.ttl = ttl_seconds

    def _key(self, entity_id: str, feature_name: str) -> str:
        return f"feature:{self.entity_type}:{entity_id}:{feature_name}"

    def write(self, entity_id: str, features: Dict[str, Any]) -> None:
        pipe = self.r.pipeline()
        for name, value in features.items():
            key = self._key(entity_id, name)
            pipe.set(key, json.dumps({"value": value, "ts": time.time()}))
            pipe.expire(key, self.ttl)
        pipe.execute()

    def read(self, entity_id: str, feature_names: List[str]) -> Dict[str, Any]:
        keys = [self._key(entity_id, n) for n in feature_names]
        raw_values = self.r.mget(keys)
        result = {}
        for name, raw in zip(feature_names, raw_values):
            if raw is not None:
                result[name] = json.loads(raw)["value"]
        return result

    def feature_age_seconds(self, entity_id: str, feature_name: str) -> Optional[float]:
        """Check how stale a feature is; alert if > freshness SLA.""\"
        key = self._key(entity_id, feature_name)
        raw = self.r.get(key)
        if raw is None:
            return None
        stored_ts = json.loads(raw)["ts"]
        return time.time() - stored_ts

import time
from dataclasses import dataclass
from typing import Optional

@dataclass
class FreshnessViolation:
    feature_name: str
    entity_id: str
    event_timestamp: float   # when the underlying event occurred
    read_timestamp: float    # when this feature was served
    max_staleness_seconds: float

    @property
    def staleness_seconds(self) -> float:
        return self.read_timestamp - self.event_timestamp

    @property
    def is_violation(self) -> bool:
        return self.staleness_seconds > self.max_staleness_seconds


class FreshnessMonitor:
    """Check freshness at serve time and emit metrics for stale features."""

    def __init__(self, slas: dict[str, float]):
        # slas maps feature_name -> max_staleness_seconds
        self.slas = slas
        self.violations: list[FreshnessViolation] = []

    def check(
        self,
        feature_name: str,
        entity_id: str,
        event_timestamp: float,
    ) -> Optional[FreshnessViolation]:
        if feature_name not in self.slas:
            return None
        v = FreshnessViolation(
            feature_name=feature_name,
            entity_id=entity_id,
            event_timestamp=event_timestamp,
            read_timestamp=time.time(),
            max_staleness_seconds=self.slas[feature_name],
        )
        if v.is_violation:
            self.violations.append(v)
            # In production: emit to Prometheus / Datadog
            print(
                f"FRESHNESS_VIOLATION feature={feature_name} "
                f"entity={entity_id} staleness={v.staleness_seconds:.1f}s "
                f"sla={v.max_staleness_seconds}s"
            )
        return v if v.is_violation else None


# Usage
monitor = FreshnessMonitor(slas={
    "user_subscription_tier": 300,
    "conversation_summary": 30,
    "user_language_preference": 3600,
})
